"user strict"; const triggerNotification = a => { $(".notification-msg-bar").find(".notification-msg").html(a), $(".notification-msg-bar").removeClass("smoothly-hide"), setTimeout(() => { $(".notification-msg-bar").addClass("smoothly-hide"), $(".notification-msg-bar").find(".notification-msg").html("") }, 1500) }; function updateDeliveryManStatusBadge() { $.ajax({ url: SITE_URL + "/status", method: "GET", success: function (a) { $(".delivery-man-status-badge").text(a.is_active ? jsLang("Online") : jsLang("Offline")).toggleClass("theme-bg-active", !0 == a.is_active).toggleClass("theme-bg-inactive", !1 == a.is_active).removeClass("spinner-border"), triggerNotification(jsLang("Successfully update your status.")) }, error: function (a) { triggerNotification(a?.responseJSON?.message ?? jsLang("Something went wrong, please try again.")) } }) } $(".delivery-man-status-badge").on("click", function () { $(this).append(`<div class="spinner-border spinner-border-sm ml-2" role="status">`), updateDeliveryManStatusBadge() });